import re
import json

businesses = locals()['var_function-call-13634299505935893796']
if isinstance(businesses, str):
    with open(businesses, 'r') as f:
        businesses = json.load(f)

wifi_businesses_by_state = {}
state_counts = {}

# Regex to extract state: looks for ", AA, this" pattern where AA is 2 uppercase letters
state_pattern = re.compile(r",\s([A-Z]{2}),\s+this")

for b in businesses:
    attrs = b.get('attributes')
    has_wifi = False

    if attrs and isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            # Clean string: u'free' -> free, 'free' -> free
            clean_val = str(wifi_val).replace("u'", "").replace("'", "").lower()
            if clean_val in ['free', 'paid']:
                has_wifi = True

    if has_wifi:
        desc = b.get('description', '')
        match = state_pattern.search(desc)
        if match:
            state = match.group(1)
            if state not in state_counts:
                state_counts[state] = 0
                wifi_businesses_by_state[state] = []
            state_counts[state] += 1
            wifi_businesses_by_state[state].append(b['business_id'])

# Find max state
if not state_counts:
    print("__RESULT__:")
    print(json.dumps({"error": "No wifi businesses found"}))
else:
    top_state = max(state_counts, key=state_counts.get)
    count = state_counts[top_state]
    ids = wifi_businesses_by_state[top_state]

    print("__RESULT__:")
    print(json.dumps({"top_state": top_state, "count": count, "business_ids": ids}))

