wifi_businesses_by_state = {}
state_counts = {}

# List of US state codes to validate
us_states = set([
    'AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 'HI', 'ID', 'IL', 'IN', 'IA', 
    'KS', 'KY', 'LA', 'ME', 'MD', 'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 
    'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 'SD', 'TN', 'TX', 'UT', 'VT', 
    'VA', 'WA', 'WV', 'WI', 'WY'
])

# Regex to find state code. 
# Matches comma, space, 2 uppercase letters, followed by comma or space and keywords.
state_pattern = re.compile(r",\s([A-Z]{2})(?:,|\s+location|\s+this|\s+facility|\s+establishment|\s+spot)")

def get_wifi_status(b):
    attrs = b.get('attributes')
    if attrs and isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            clean_val = str(wifi_val).replace("u'", "").replace("'", "").lower()
            if clean_val in ['free', 'paid']:
                return True
    return False

def get_state(description):
    # Try the standard "in City, ST," pattern
    match = state_pattern.search(description)
    if match:
        state = match.group(1)
        if state in us_states:
            return state
    # Fallback for "This City, ST location"
    # Look for "City, ST location"
    match2 = re.search(r",\s([A-Z]{2})\s+location", description)
    if match2:
        state = match2.group(1)
        if state in us_states:
            return state

    # Fallback: Just look for ", ST," if it's in the states list
    matches = re.findall(r",\s([A-Z]{2})", description)
    for m in matches:
        if m in us_states:
            return m

    return None

with open(businesses_file, 'r') as f:
    businesses = json.load(f)

for b in businesses:
    if get_wifi_status(b):
        desc = b.get('description', '')
        state = get_state(desc)
        if state:
            if state not in state_counts:
                state_counts[state] = 0
                wifi_businesses_by_state[state] = []
            state_counts[state] += 1
            wifi_businesses_by_state[state].append(b['business_id'])

if not state_counts:
    print("__RESULT__:")
    print(json.dumps({"error": "No wifi businesses found"}))
else:
    top_state = max(state_counts, key=state_counts.get)
    count = state_counts[top_state]
    ids = wifi_businesses_by_state[top_state]

    # Only return top state info
    print("__RESULT__:")
    print(json.dumps({"top_state": top_state, "count": count, "business_ids": ids}))

